  1	import { type FC, useMemo } from 'react';
  2	import { Controller, useWatch } from 'react-hook-form';
  3	import { useNamespaces as useProviderNamespaces } from 'src/modules/Providers/hooks/useNamespaces';
  4	
  5	import FormGroupWithErrorText from '@components/common/FormGroupWithErrorText';
  6	import { HelpIconPopover } from '@components/common/HelpIconPopover/HelpIconPopover';
  7	import ProjectSelect from '@components/common/ProjectSelect/ProjectSelect';
  8	import { MenuToggleStatus, Stack, StackItem } from '@patternfly/react-core';
  9	import { getName } from '@utils/crds/common/selectors';
 10	import { ForkliftTrans, useForkliftTranslation } from '@utils/i18n';
 11	
 12	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
 13	
 14	import { GeneralFormFieldId, generalFormFieldLabels } from './constants';
 15	
 16	type TargetProjectFieldProps = {
 17	  testId?: string;
 18	};
 19	
 20	const TargetProjectField: FC<TargetProjectFieldProps> = ({ testId = 'target-project-select' }) => {
 21	  const { t } = useForkliftTranslation();
 22	  const {
 23	    control,
 24	    formState: { errors },
 25	    setValue,
 26	  } = useCreatePlanFormContext();
 27	  const targetProvider = useWatch({
 28	    control,
 29	    name: GeneralFormFieldId.TargetProvider,
 30	  });
 31	  const targetProviderName = getName(targetProvider);
 32	  const [targetProviderProjects, , , forceRefresh] = useProviderNamespaces(targetProvider);
 33	  const showDefaultProjects =
 34	    useWatch({ control, name: GeneralFormFieldId.ShowDefaultProjects }) ?? false;
 35	
 36	  const targetProjectNames = useMemo(
 37	    () => targetProviderProjects.map((project) => project.name),
 38	    [targetProviderProjects],
 39	  );
 40	
 41	  return (
 42	    <FormGroupWithErrorText
 43	      isRequired
 44	      fieldId={GeneralFormFieldId.TargetProject}
 45	      label={generalFormFieldLabels[GeneralFormFieldId.TargetProject]}
 46	      labelIcon={
 47	        <HelpIconPopover>
 48	          <Stack hasGutter>
 49	            <StackItem>
 50	              {t(
 51	                'The target project is the project, within your selected target provider, that your virtual machines will be migrated to. This is different from the project that your migration plan will be created in and where your provider was created.',
 52	              )}
 53	            </StackItem>
 54	            <StackItem>
 55	              {t('Projects, also known as namespaces, separate resources within clusters.')}
 56	            </StackItem>
 57	          </Stack>
 58	        </HelpIconPopover>
 59	      }
 60	    >
 61	      <Controller
 62	        name={GeneralFormFieldId.TargetProject}
 63	        control={control}
 64	        render={({ field }) => (
 65	          <ProjectSelect
 66	            testId={testId}
 67	            isDisabled={!targetProvider}
 68	            placeholder={
 69	              targetProvider
 70	                ? t('Select target project')
 71	                : t('Must choose a target provider to see available target projects')
 72	            }
 73	            id={GeneralFormFieldId.TargetProject}
 74	            projectNames={targetProjectNames}
 75	            emptyStateMessage={
 76	              targetProviderName ? (
 77	                <ForkliftTrans>
 78	                  Target provider <strong>{targetProviderName}</strong> does not have network
 79	                  mappings available in any existing projects.
 80	                  <br />
 81	                  Create a project or select a different target provider.
 82	                </ForkliftTrans>
 83	              ) : null
 84	            }
 85	            value={field.value}
 86	            onChange={field.onChange}
 87	            onNewValue={(newProjectName) => {
 88	              forceRefresh();
 89	              setValue(GeneralFormFieldId.TargetProject, newProjectName);
 90	            }}
 91	            showDefaultProjects={Boolean(showDefaultProjects)}
 92	            setShowDefaultProjects={(value) => {
 93	              setValue(GeneralFormFieldId.ShowDefaultProjects, value);
 94	            }}
 95	            noOptionsMessage={
 96	              targetProvider
 97	                ? undefined
 98	                : t('Select a target provider to list available target projects')
 99	            }
100	            toggleProps={{
101	              id: 'target-project-select',
102	              status: errors[GeneralFormFieldId.TargetProject] && MenuToggleStatus.danger,
103	            }}
104	          />
105	        )}
106	        rules={{ required: t('Target project is required.') }}
107	      />
108	    </FormGroupWithErrorText>
109	  );
110	};
111	
112	export default TargetProjectField;

